xpath.script:
                    (function () {
                        'use strict';

                        /* ════════════════════════════════════════
                           ESTADO TEMPORAL — NO se crea la cuenta
                           hasta que el usuario complete todo.
                        ════════════════════════════════════════ */
                        var pendingSignup = {
                            firstName: '',
                            email:     '',
                            password:  ''
                        };

                        /* ── Elementos: login ── */
                        var loginOverlay  = document.getElementById('kualeLoginOverlay');
                        var loginClose    = document.getElementById('kualeLoginClose');
                        var loginForm     = document.getElementById('kualeLoginForm');
                        var loginError    = document.getElementById('kualeLoginError');
                        var loginSubmit   = document.getElementById('kualeLoginSubmit');
                        var forgotBtn     = document.getElementById('kualeForgotBtn');
                        var goToSignup    = document.getElementById('kualeGoToSignup');

                        /* ── Elementos: signup ── */
                        var signupOverlay = document.getElementById('kualeSignupOverlay');
                        var signupClose   = document.getElementById('kualeSignupClose');
                        var signupForm    = document.getElementById('kualeSignupForm');
                        var signupError   = document.getElementById('kualeSignupError');
                        var signupSubmit  = document.getElementById('kualeSignupSubmit');
                        var goToLogin     = document.getElementById('kualeGoToLogin');

                        /* ── Elementos: verificación ── */
                        var verifyOverlay   = document.getElementById('kualeVerifyOverlay');
                        var verifyClose     = document.getElementById('kualeVerifyClose');
                        var verifyError     = document.getElementById('kualeVerifyError');
                        var verifySuccess   = document.getElementById('kualeVerifySuccess');
                        var verifySubmit    = document.getElementById('kualeVerifySubmit');
                        var verifyBack      = document.getElementById('kualeVerifyBack');
                        var timerDisplay    = document.getElementById('kualeTimerDisplay');
                        var timerWrap       = document.getElementById('kualeTimerWrap');
                        var resendWrap      = document.getElementById('kualeResendWrap');
                        var resendBtn       = document.getElementById('kualeResendBtn');
                        var verifyEmailDisp = document.getElementById('kualeVerifyEmailDisplay');
                        var verifyDigits    = document.querySelectorAll('.kuale-verify-digit');

                        /* ── Elementos: perfil ── */
                        var perfilOverlay   = document.getElementById('kualePerfilOverlay');
                        var perfilForm      = document.getElementById('kualePerfilForm');
                        var perfilError     = document.getElementById('kualePerfilError');
                        var perfilSubmit    = document.getElementById('kualePerfilSubmit');
                        var perfilTitle     = document.getElementById('kualePerfilTitle');
                        var perfilSubtitle  = document.getElementById('kualePerfilSubtitle');

                        /* ── Elementos: forgot ── */
                        var forgotOverlay = document.getElementById('kualeForgotOverlay');
                        var forgotClose   = document.getElementById('kualeForgotClose');
                        var forgotForm    = document.getElementById('kualeForgotForm');
                        var forgotError   = document.getElementById('kualeForgotError');
                        var forgotSuccess = document.getElementById('kualeForgotSuccess');
                        var forgotSubmit  = document.getElementById('kualeForgotSubmit');
                        var backToLogin   = document.getElementById('kualeBackToLogin');

                        /* ════════════════════════════════
                           TIMER — 5 minutos (300 segundos)
                        ════════════════════════════════ */
                        var timerInterval = null;
                        var timerSeconds  = 0;

                        function formatTime(secs) {
                            var m = Math.floor(secs / 60);
                            var s = secs % 60;
                            return m + ':' + (s < 10 ? '0' : '') + s;
                        }

                        function startTimer() {
                            stopTimer();
                            timerSeconds = 300; // 5 minutos
                            timerDisplay.textContent = formatTime(timerSeconds);
                            timerDisplay.classList.remove('warning');
                            timerWrap.style.display  = '';
                            resendWrap.style.display  = 'none';
                            resendBtn.disabled        = false;

                            timerInterval = setInterval(function () {
                                timerSeconds--;
                                timerDisplay.textContent = formatTime(timerSeconds);

                                if (timerSeconds <= 60) {
                                    timerDisplay.classList.add('warning');
                                }

                                if (timerSeconds <= 0) {
                                    stopTimer();
                                    timerWrap.style.display  = 'none';
                                    resendWrap.style.display  = '';
                                    verifySubmit.disabled     = true;
                                    showMsg(verifyError, 'El c\xF3digo expir\xF3. Por favor solicita uno nuevo.');
                                }
                            }, 1000);
                        }

                        function stopTimer() {
                            if (timerInterval) { clearInterval(timerInterval); timerInterval = null; }
                        }

                        /* ════════════════
                           HELPERS
                        ════════════════ */
                        function closeAll() {
                            loginOverlay.classList.remove('is-open');
                            signupOverlay.classList.remove('is-open');
                            verifyOverlay.classList.remove('is-open');
                            forgotOverlay.classList.remove('is-open');
                            perfilOverlay.classList.remove('is-open');
                            stopTimer();
                        }
                        function showMsg(el, msg) { el.textContent = msg; el.classList.add('is-visible'); }
                        function hideMsg(el) { el.classList.remove('is-visible'); el.textContent = ''; }

                        function getVerifyCode() {
                            return Array.from(verifyDigits).map(function (d) { return d.value; }).join('');
                        }
                        function clearVerifyCode() {
                            verifyDigits.forEach(function (d) {
                                d.value = '';
                                d.classList.remove('filled');
                            });
                        }

                        /* ════════════════
                        HELPERS
                        ════════════════ */
                        function isMobile() {
                            return window.innerWidth <= 768;
                        }

                        /* ════════════════
                        ABRIR MODALES
                        ════════════════ */
                        function openLogin() {
                            closeAll();
                            loginOverlay.classList.add('is-open');
                            hideMsg(loginError);
                            setTimeout(function () {
                                if (isMobile()) return;
                                var el = document.getElementById('kualeLoginUser');
                                if (el) el.focus();
                            }, 50);
                        }

                        function openSignup() {
                            closeAll();
                            signupOverlay.classList.add('is-open');
                            hideMsg(signupError);
                            setTimeout(function () {
                                if (isMobile()) return;
                                var el = document.getElementById('kualeSignupName');
                                if (el) el.focus();
                            }, 50);
                        }

                        function openVerify(email) {
                            closeAll();
                            verifyOverlay.classList.add('is-open');
                            hideMsg(verifyError);
                            hideMsg(verifySuccess);
                            clearVerifyCode();
                            verifySubmit.disabled       = false;
                            verifyEmailDisp.textContent = email || pendingSignup.email;
                            startTimer();
                            setTimeout(function () {
                                if (isMobile()) return;
                                if (verifyDigits[0]) verifyDigits[0].focus();
                            }, 50);
                        }

                        function openPerfil(modo) {
                            closeAll();
                            modo = modo || 'registro';
                            perfilOverlay.classList.add('is-open');
                            perfilOverlay.setAttribute('data-modo', modo);
                            hideMsg(perfilError);

                            if (modo === 'cuenta') {
                                if (perfilTitle)    perfilTitle.textContent    = 'Mi cuenta';
                                if (perfilSubtitle) perfilSubtitle.textContent = 'Actualiza tus datos de contacto.';
                                if (perfilSubmit)   perfilSubmit.textContent   = 'Guardar';

                                fetch('/kuale/perfil/datos', {
                                    method: 'POST',
                                    headers: { 'Content-Type': 'application/json' },
                                    body: JSON.stringify({ jsonrpc: '2.0', method: 'call', params: {} })
                                })
                                .then(function (r) { return r.json(); })
                                .then(function (data) {
                                    var d = data.result || {};
                                    var fn = document.getElementById('kpFirstName');  
                                    var ln = document.getElementById('kpLastName');
                                    var sl = document.getElementById('kpSecondLast');
                                    var ph = document.getElementById('kpPhone');
                                    var zp = document.getElementById('kpZip');
                                    if (fn) fn.value = d.kuale_first_name  || '';     
                                    if (ln) ln.value = d.kuale_last_name   || '';
                                    if (sl) sl.value = d.kuale_second_last || '';
                                    if (ph) ph.value = d.phone             || '';
                                    if (zp) zp.value = d.zip               || '';
                                })
                                .catch(function () {});

                            } else {
                                if (perfilTitle)    perfilTitle.innerHTML      = '👋 ¡Casi listo!';
                                if (perfilSubtitle) perfilSubtitle.textContent = 'Completa tu perfil para poder postularte a vacantes.';
                                if (perfilSubmit)   perfilSubmit.textContent   = 'Crear cuenta';

                                ['kpLastName','kpSecondLast','kpPhone','kpZip'].forEach(function (id) {
                                    var el = document.getElementById(id);
                                    if (el) el.value = '';
                                });
                            }

                            setTimeout(function () {
                                if (isMobile()) return;
                                var el = document.getElementById('kpLastName');
                                if (el) el.focus();
                            }, 50);
                        }

                        function openForgot() {
                            closeAll();
                            forgotOverlay.classList.add('is-open');
                            hideMsg(forgotError);
                            hideMsg(forgotSuccess);
                            forgotForm.style.display = '';
                            var fe = document.getElementById('kualeForgotEmail');
                            if (fe) {
                                fe.value = '';
                                if (!isMobile()) fe.focus();
                            }
                        }

                        function showLoginError(msg) {
                            showMsg(loginError, msg);
                            var u = document.getElementById('kualeLoginUser');
                            var p = document.getElementById('kualeLoginPass');
                            if (u) { u.value = ''; if (!isMobile()) u.focus(); }
                            if (p) { p.value = ''; }
                        }

                        /* ════════════════════════════════════════
                           INPUT de 6 dígitos — navegación entre cajas
                        ════════════════════════════════════════ */
                        verifyDigits.forEach(function (input, idx) {
                            input.addEventListener('keydown', function (e) {
                                if (e.key === 'Backspace') {
                                    if (input.value === '' && idx > 0) {
                                        verifyDigits[idx - 1].value = '';
                                        verifyDigits[idx - 1].classList.remove('filled');
                                        verifyDigits[idx - 1].focus();
                                    } else {
                                        input.value = '';
                                        input.classList.remove('filled');
                                    }
                                    e.preventDefault();
                                    return;
                                }
                                if (e.key === 'ArrowLeft' && idx > 0) { verifyDigits[idx - 1].focus(); return; }
                                if (e.key === 'ArrowRight' && idx < 5) { verifyDigits[idx + 1].focus(); return; }
                            });

                            input.addEventListener('input', function (e) {
                                /* Solo dígitos */
                                var val = input.value.replace(/\D/g, '');
                                /* Pegar: distribuir dígitos */
                                if (val.length > 1) {
                                    var digits = val.split('');
                                    digits.forEach(function (d, i) {
                                        if (idx + i < 6) {
                                            verifyDigits[idx + i].value = d;
                                            verifyDigits[idx + i].classList.add('filled');
                                        }
                                    });
                                    var next = Math.min(idx + digits.length, 5);
                                    verifyDigits[next].focus();
                                } else {
                                    input.value = val;
                                    if (val) {
                                        input.classList.add('filled');
                                        if (idx < 5) verifyDigits[idx + 1].focus();
                                    } else {
                                        input.classList.remove('filled');
                                    }
                                }
                            });

                            /* Seleccionar todo al enfocar */
                            input.addEventListener('focus', function () { input.select(); });
                        });

                        /* ════════════════════════════
                           TRIGGERS GLOBALES
                        ════════════════════════════ */
                        document.addEventListener('click', function (e) {
                            var loginTrigger  = e.target.closest('[data-kuale-login="open"]');
                            var signupTrigger = e.target.closest('[data-kuale-signup="open"]');
                            var perfilTrigger = e.target.closest('[data-kuale-perfil="open"]');
                            if (loginTrigger)  { e.preventDefault(); e.stopPropagation(); openLogin(); }
                            if (signupTrigger) { e.preventDefault(); e.stopPropagation(); openSignup(); }
                            if (perfilTrigger) { e.preventDefault(); e.stopPropagation(); openPerfil('cuenta'); }
                        }, true);

                        /* ── Cerrar con X ── */
                        loginClose.addEventListener('click',  closeAll);
                        signupClose.addEventListener('click', closeAll);
                        forgotClose.addEventListener('click', closeAll);
                        verifyClose.addEventListener('click', function () { stopTimer(); closeAll(); });

                        /* ── Cerrar al click fuera ── */
                        loginOverlay.addEventListener('click',  function (e) { if (e.target === loginOverlay)  closeAll(); });
                        signupOverlay.addEventListener('click', function (e) { if (e.target === signupOverlay) closeAll(); });
                        forgotOverlay.addEventListener('click', function (e) { if (e.target === forgotOverlay) closeAll(); });
                        verifyOverlay.addEventListener('click', function (e) { if (e.target === verifyOverlay) { stopTimer(); closeAll(); } });
                        perfilOverlay.addEventListener('click', function (e) {
                            if (e.target === perfilOverlay && perfilOverlay.getAttribute('data-modo') === 'cuenta') {
                                closeAll();
                            }
                        });

                        /* ── Escape ── */
                        document.addEventListener('keydown', function (e) {
                            if (e.key === 'Escape') {
                                var modo = perfilOverlay.getAttribute('data-modo');
                                if (perfilOverlay.classList.contains('is-open') && modo === 'registro') return;
                                stopTimer();
                                closeAll();
                            }
                        });

                        /* ── Navegación entre modales ── */
                        forgotBtn.addEventListener('click',   function (e) { e.preventDefault(); openForgot(); });
                        goToSignup.addEventListener('click',  function (e) { e.preventDefault(); openSignup(); });
                        goToLogin.addEventListener('click',   function (e) { e.preventDefault(); openLogin(); });
                        backToLogin.addEventListener('click', function (e) { e.preventDefault(); openLogin(); });
                        verifyBack.addEventListener('click',  function (e) { e.preventDefault(); stopTimer(); openSignup(); });

                        /* ════════════════════════════════
                           SUBMIT: LOGIN
                        ════════════════════════════════ */
                        loginForm.addEventListener('submit', function (e) {
                            e.preventDefault();
                            hideMsg(loginError);
                            var login    = document.getElementById('kualeLoginUser').value.trim();
                            var password = document.getElementById('kualeLoginPass').value;
                            if (!login || !password) { showLoginError('Por favor completa todos los campos.'); return; }
                            loginSubmit.disabled = true;
                            loginSubmit.textContent = 'Entrando...';
                            fetch('/kuale/login/ajax', {
                                method: 'POST',
                                headers: { 'Content-Type': 'application/json' },
                                body: JSON.stringify({ jsonrpc: '2.0', method: 'call', params: { login: login, password: password } })
                            })
                            .then(function (r) { return r.json(); })
                            .then(function (data) {
                                var result = data.result || {};
                                if (result.success) {
                                    window.location.href = result.redirect || '/jobs';
                                } else {
                                    showLoginError(result.error || 'Usuario o contrase\xF1a incorrectos.');
                                    loginSubmit.disabled = false;
                                    loginSubmit.textContent = 'Entrar';
                                }
                            })
                            .catch(function () {
                                showLoginError('Error de conexi\xF3n. Intenta de nuevo.');
                                loginSubmit.disabled = false;
                                loginSubmit.textContent = 'Entrar';
                            });
                        });

                        /* ════════════════════════════════════════════════════════════
                           SUBMIT: SIGNUP
                           ─ Solo valida y ENVÍA el código al correo.
                           ─ NO crea la cuenta todavía.
                        ════════════════════════════════════════════════════════════ */
                        signupForm.addEventListener('submit', function (e) {
                            e.preventDefault();
                            hideMsg(signupError);
                            var email     = document.getElementById('kualeSignupEmail').value.trim();
                            var pass      = document.getElementById('kualeSignupPass').value;
                            var pass2     = document.getElementById('kualeSignupPass2').value;

                            if (!email || !pass || !pass2) {
                                showMsg(signupError, 'Por favor completa todos los campos.');
                                return;
                            }
                            if (pass !== pass2) {
                                showMsg(signupError, 'Las contrase\xF1as no coinciden.');
                                var sp  = document.getElementById('kualeSignupPass');
                                var sp2 = document.getElementById('kualeSignupPass2');
                                if (sp)  { sp.value = '';  sp.focus(); }
                                if (sp2) { sp2.value = ''; }
                                return;
                            }
                            if (pass.length < 8) {
                                showMsg(signupError, 'La contrase\xF1a debe tener al menos 8 caracteres.');
                                var sp  = document.getElementById('kualeSignupPass');
                                var sp2 = document.getElementById('kualeSignupPass2');
                                if (sp)  { sp.value = '';  sp.focus(); }
                                if (sp2) { sp2.value = ''; }
                                return;
                            }

                            signupSubmit.disabled = true;
                            signupSubmit.textContent = 'Enviando c\xF3digo...';

                            /* Guardar datos en memoria — la cuenta se crea al final */
                            pendingSignup.email     = email;
                            pendingSignup.password  = pass;

                            /* Llamar al endpoint que solo envía el código */
                            fetch('/kuale/send_verification', {
                                method: 'POST',
                                headers: { 'Content-Type': 'application/json' },
                                body: JSON.stringify({
                                    jsonrpc: '2.0', method: 'call',
                                    params: { email: email }
                                })
                            })
                            .then(function (r) { return r.json(); })
                            .then(function (data) {
                                var result = data.result || {};
                                signupSubmit.disabled = false;
                                signupSubmit.textContent = 'Continuar';
                                if (result.success) {
                                    openVerify(email);
                                } else {
                                    showMsg(signupError, result.error || 'Error al enviar el c\xF3digo. Intenta de nuevo.');
                                }
                            })
                            .catch(function () {
                                showMsg(signupError, 'Error de conexi\xF3n. Intenta de nuevo.');
                                signupSubmit.disabled = false;
                                signupSubmit.textContent = 'Continuar';
                            });
                        });

                        /* ════════════════════════════════════════════════════
                           REENVIAR CÓDIGO
                        ════════════════════════════════════════════════════ */
                        function enviarCodigo(email, onSuccess, onError) {
                            fetch('/kuale/send_verification', {
                                method: 'POST',
                                headers: { 'Content-Type': 'application/json' },
                                body: JSON.stringify({
                                    jsonrpc: '2.0', method: 'call',
                                    params: { email: email }
                                })
                            })
                            .then(function (r) { return r.json(); })
                            .then(function (data) {
                                var result = data.result || {};
                                if (result.success) { onSuccess(); }
                                else { onError(result.error || 'Error al enviar el c\xF3digo.'); }
                            })
                            .catch(function () { onError('Error de conexi\xF3n. Intenta de nuevo.'); });
                        }

                        resendBtn.addEventListener('click', function () {
                            resendBtn.disabled = true;
                            resendBtn.textContent = 'Enviando...';
                            hideMsg(verifyError);
                            hideMsg(verifySuccess);
                            clearVerifyCode();

                            enviarCodigo(
                                pendingSignup.email,
                                function () {
                                    /* Éxito: reiniciar timer */
                                    resendBtn.textContent = 'Reenviar c\xF3digo';
                                    verifySubmit.disabled = false;
                                    showMsg(verifySuccess, 'C\xF3digo enviado. Revisa tu correo.');
                                    startTimer();
                                    if (verifyDigits[0]) verifyDigits[0].focus();
                                },
                                function (err) {
                                    resendBtn.textContent = 'Reenviar c\xF3digo';
                                    resendBtn.disabled    = false;
                                    showMsg(verifyError, err);
                                }
                            );
                        });

                        /* ════════════════════════════════════════════════════════════
                           SUBMIT: VERIFICAR CÓDIGO
                           ─ Valida el código con el servidor.
                           ─ Si es correcto, abre el modal de perfil.
                           ─ La cuenta sigue SIN crearse.
                        ════════════════════════════════════════════════════════════ */
                        verifySubmit.addEventListener('click', function () {
                            hideMsg(verifyError);
                            var code = getVerifyCode();
                            if (code.length < 6) {
                                showMsg(verifyError, 'Ingresa los 6 d\xEDgitos del c\xF3digo.');
                                if (verifyDigits[0]) verifyDigits[0].focus();
                                return;
                            }
                            verifySubmit.disabled = true;
                            verifySubmit.textContent = 'Verificando...';

                            fetch('/kuale/verify_code', {
                                method: 'POST',
                                headers: { 'Content-Type': 'application/json' },
                                body: JSON.stringify({
                                    jsonrpc: '2.0', method: 'call',
                                    params: { email: pendingSignup.email, code: code }
                                })
                            })
                            .then(function (r) { return r.json(); })
                            .then(function (data) {
                                var result = data.result || {};
                                verifySubmit.disabled = false;
                                verifySubmit.textContent = 'Verificar';
                                if (result.success) {
                                    stopTimer();
                                    openPerfil('registro'); // ← ahora sí, pedir datos
                                } else {
                                    clearVerifyCode();
                                    showMsg(verifyError, result.error || 'C\xF3digo incorrecto. Intenta de nuevo.');
                                    if (verifyDigits[0]) verifyDigits[0].focus();
                                }
                            })
                            .catch(function () {
                                showMsg(verifyError, 'Error de conexi\xF3n. Intenta de nuevo.');
                                verifySubmit.disabled = false;
                                verifySubmit.textContent = 'Verificar';
                            });
                        });

                        /* ════════════════════════════════════════════════════════════
                        SUBMIT: PERFIL
                        MODO REGISTRO: Aquí se crea la cuenta con TODOS los datos.
                        MODO CUENTA:   Actualiza los datos (el usuario ya existe).
                        ════════════════════════════════════════════════════════════ */
                        perfilForm.addEventListener('submit', function (e) {
                            e.preventDefault();
                            hideMsg(perfilError);

                            var firstName  = document.getElementById('kpFirstName').value.trim();  // ← NUEVO
                            var lastName   = document.getElementById('kpLastName').value.trim();
                            var secondLast = document.getElementById('kpSecondLast').value.trim();
                            var phone      = document.getElementById('kpPhone').value.trim();
                            var zip        = document.getElementById('kpZip').value.trim();

                            if (!firstName || !lastName || !secondLast || !phone || !zip) {  // ← firstName incluido
                                showMsg(perfilError, 'Por favor completa todos los campos.');
                                return;
                            }

                            var modo = perfilOverlay.getAttribute('data-modo') || 'registro';
                            perfilSubmit.disabled = true;
                            perfilSubmit.textContent = 'Guardando...';

                            if (modo === 'registro') {
                                /* ── CREAR CUENTA: se envían TODOS los datos juntos ── */
                                fetch('/kuale/signup/ajax', {
                                    method: 'POST',
                                    headers: { 'Content-Type': 'application/json' },
                                    body: JSON.stringify({
                                        jsonrpc: '2.0', method: 'call',
                                        params: {
                                            name:              firstName + ' ' + lastName,  // ← nombre completo
                                            login:             pendingSignup.email,
                                            password:          pendingSignup.password,
                                            confirm_password:  pendingSignup.password,
                                            kuale_first_name:  firstName,                   // ← del perfil
                                            kuale_last_name:   lastName,
                                            kuale_second_last: secondLast,
                                            phone:             phone,
                                            zip:               zip
                                        }
                                    })
                                })
                                .then(function (r) { return r.json(); })
                                .then(function (data) {
                                    var result = data.result || {};
                                    if (result.success) {
                                        /* Limpiar datos temporales */
                                        pendingSignup = { firstName: '', email: '', password: '' };
                                        window.location.href = result.redirect || '/vacantes';
                                    } else {
                                        showMsg(perfilError, result.error || 'Error al crear la cuenta.');
                                        perfilSubmit.disabled = false;
                                        perfilSubmit.textContent = 'Crear cuenta';
                                    }
                                })
                                .catch(function () {
                                    showMsg(perfilError, 'Error de conexi\xF3n. Intenta de nuevo.');
                                    perfilSubmit.disabled = false;
                                    perfilSubmit.textContent = 'Crear cuenta';
                                });

                            } else {
                                /* ── ACTUALIZAR datos de cuenta existente ── */
                                fetch('/kuale/perfil/ajax', {
                                    method: 'POST',
                                    headers: { 'Content-Type': 'application/json' },
                                    body: JSON.stringify({
                                        jsonrpc: '2.0', method: 'call',
                                        params: {
                                            kuale_first_name:  firstName,   // ← también se actualiza
                                            kuale_last_name:   lastName,
                                            kuale_second_last: secondLast,
                                            phone:             phone,
                                            zip:               zip
                                        }
                                    })
                                })
                                .then(function (r) { return r.json(); })
                                .then(function (data) {
                                    var result = data.result || {};
                                    if (result.success) {
                                        closeAll();
                                        perfilSubmit.disabled = false;
                                        perfilSubmit.textContent = 'Guardar';
                                    } else {
                                        showMsg(perfilError, result.error || 'Error al guardar.');
                                        perfilSubmit.disabled = false;
                                        perfilSubmit.textContent = 'Guardar';
                                    }
                                })
                                .catch(function () {
                                    showMsg(perfilError, 'Error de conexi\xF3n. Intenta de nuevo.');
                                    perfilSubmit.disabled = false;
                                    perfilSubmit.textContent = 'Guardar';
                                });
                            }
                        });

                        /* ════════════════════════════════
                           SUBMIT: FORGOT PASSWORD
                        ════════════════════════════════ */
                        forgotForm.addEventListener('submit', function (e) {
                            e.preventDefault();
                            hideMsg(forgotError);
                            hideMsg(forgotSuccess);
                            var email = document.getElementById('kualeForgotEmail').value.trim();
                            if (!email) { showMsg(forgotError, 'Por favor ingresa tu correo electr\xF3nico.'); return; }
                            forgotSubmit.disabled = true;
                            forgotSubmit.textContent = 'Enviando...';
                            fetch('/web/reset_password', {
                                method: 'POST',
                                headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
                                body: new URLSearchParams({
                                    login: email,
                                    csrf_token: forgotForm.querySelector('[name="csrf_token"]').value
                                })
                            })
                            .then(function () {
                                showMsg(forgotSuccess, 'Si tu correo est\xE1 registrado, recibir\xE1s un enlace en breve.');
                                forgotForm.style.display = 'none';
                                forgotSubmit.disabled = false;
                                forgotSubmit.textContent = 'Enviar enlace';
                            })
                            .catch(function () {
                                showMsg(forgotError, 'Error al enviar. Intenta de nuevo.');
                                forgotSubmit.disabled = false;
                                forgotSubmit.textContent = 'Enviar enlace';
                            });
                        });

                        /* ── Auto-abrir si hay error de login ── */
                        if (window.location.search.indexOf('login_error=1') !== -1) {
                            openLogin();
                            showLoginError('Usuario o contrase\xF1a incorrectos.');
                        }

                    })();
